const emptyLine = { fontFamily: "Inter, sans-serif", fontSize: 14, color: C.inkSoft, padding: "10px 0" };
const overlay = { position: "fixed", inset: 0, background: "rgba(19,73,94,0.45)", display: "flex", alignItems: "center", justifyContent: "center", padding: 16, zIndex: 50 };
const modal = { background: C.card, borderRadius: 18, padding: 24, width: "100%", maxWidth: 460, maxHeight: "92vh", overflowY: "auto", boxShadow: "0 20px 60px rgba(0,0,0,0.25)" };
const drawer = { background: C.card, borderRadius: 18, padding: 24, width: "100%", maxWidth: 540, maxHeight: "92vh", overflowY: "auto", boxShadow: "0 20px 60px rgba(0,0,0,0.25)" };
const toastStyle = { position: "fixed", bottom: 24, left: "50%", transform: "translateX(-50%)", background: C.tealDark, color: "#fff", padding: "12px 22px", borderRadius: 999, fontSize: 14, fontFamily: "Inter, sans-serif", fontWeight: 500, zIndex: 60, boxShadow: "0 8px 24px rgba(0,0,0,0.25)" };
